<?php
require_once 'config.php';require_auth();ensure_schema();$pageTitle='Clientes y motos';$pdo=db();$error=null;
if(is_post()){try{verify_csrf();$a=(string)post('action');if($a==='create'){$name=clean_text(post('name'));$phone=clean_text(post('phone'));if($name===''||$phone==='')throw new RuntimeException('Nombre y teléfono son obligatorios.');$st=$pdo->prepare('INSERT INTO clients(name,phone,email,dni,address,notes) VALUES(?,?,?,?,?,?)');$st->execute([$name,$phone,nullable_text(post('email')),nullable_text(post('dni')),nullable_text(post('address')),nullable_text(post('notes'))]);$id=(int)$pdo->lastInsertId();flash('success','Cliente creado. Ahora podés registrar sus motos.');redirect('client_view.php?id='.$id);}if(in_array($a,['deactivate','restore'],true)){$active=$a==='restore'?1:0;$st=$pdo->prepare('UPDATE clients SET active=? WHERE id=?');$st->execute([$active,(int)post('id')]);flash('success',$active?'Cliente restaurado.':'Cliente archivado sin perder el historial.');redirect('clients.php?status='.($active?'active':'archived'));}}catch(Throwable $e){$error=$e->getMessage();}}
$q=clean_text($_GET['q']??'');$status=($_GET['status']??'active')==='archived'?'archived':'active';$like="%$q%";$st=$pdo->prepare('SELECT c.*,(SELECT COUNT(*) FROM vehicles v WHERE v.client_id=c.id AND v.active=1) vehicle_count,(SELECT COUNT(*) FROM work_orders wo WHERE wo.client_id=c.id) order_count FROM clients c WHERE c.active=? AND (c.name LIKE ? OR c.phone LIKE ? OR c.dni LIKE ? OR c.email LIKE ?) ORDER BY c.updated_at DESC,c.name');$st->execute([$status==='active'?1:0,$like,$like,$like,$like]);$rows=$st->fetchAll();include 'partials/header.php';?>
<div class="page-head"><div class="page-head-copy"><h1>Clientes y motos</h1><p>Cada cliente conserva sus motos y su historial de reparaciones.</p></div></div><?php if($error):?><div class="alert alert-error"><span><?=h($error)?></span></div><?php endif;?><div class="grid">
<section class="card span4"><div class="card-header"><div><h2>Nuevo cliente</h2><p>Después podrás cargar una o más motos.</p></div></div><form method="post" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="create"><div class="field"><label class="required">Nombre completo</label><input name="name" required value="<?=h(post('name'))?>"></div><div class="field"><label class="required">Teléfono</label><input name="phone" required value="<?=h(post('phone'))?>"></div><div class="field"><label>Email</label><input type="email" name="email" value="<?=h(post('email'))?>"></div><div class="field"><label>DNI</label><input name="dni" value="<?=h(post('dni'))?>"></div><div class="field"><label>Dirección</label><input name="address" value="<?=h(post('address'))?>"></div><div class="field"><label>Notas</label><textarea name="notes"><?=h(post('notes'))?></textarea></div><div class="form-actions"><button class="btn btn-primary">Guardar cliente</button></div></form></section>
<section class="card span8"><div class="card-header"><div><h2><?=$status==='active'?'Clientes activos':'Clientes archivados'?></h2><p><?=count($rows)?> registro<?=count($rows)===1?'':'s'?></p></div></div><form class="toolbar" method="get"><div class="search"><input name="q" value="<?=h($q)?>" placeholder="Buscar nombre, teléfono, DNI o email"></div><select name="status"><option value="active" <?=$status==='active'?'selected':''?>>Activos</option><option value="archived" <?=$status==='archived'?'selected':''?>>Archivados</option></select><button class="btn">Filtrar</button></form>
<?php if($rows):?><div class="table-wrap responsive"><table><thead><tr><th>Cliente</th><th>Contacto</th><th>Motos</th><th>Órdenes</th><th>Actualizado</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td class="primary-cell"><strong><?=h($r['name'])?></strong><br><small class="muted">DNI <?=h($r['dni']?:'no cargado')?></small></td><td data-label="Contacto"><?=h($r['phone'])?><br><small class="muted"><?=h($r['email']?:'Sin email')?></small></td><td data-label="Motos"><span class="badge"><?=(int)$r['vehicle_count']?></span></td><td data-label="Órdenes"><span class="badge"><?=(int)$r['order_count']?></span></td><td data-label="Actualizado"><?=h(date_ar($r['updated_at'],true))?></td><td data-label="Acciones"><div class="table-actions"><a class="btn btn-sm" href="client_view.php?id=<?=(int)$r['id']?>">Ver ficha</a><form method="post" data-confirm="<?=$status==='active'?'¿Archivar este cliente?':'¿Restaurar este cliente?'?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=(int)$r['id']?>"><input type="hidden" name="action" value="<?=$status==='active'?'deactivate':'restore'?>"><button class="btn btn-sm <?=$status==='active'?'btn-danger':'btn-success'?>"><?=$status==='active'?'Archivar':'Restaurar'?></button></form></div></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="empty-state"><div><div class="empty-icon">👤</div><h2>No hay clientes</h2><p class="muted">Cambiá el filtro o cargá uno nuevo.</p></div></div><?php endif;?></section></div><?php include 'partials/footer.php';?>
